// Extract features from ArcGIS response into flat objects
const features = $input.first().json.features ?? [];
return features
  .filter(f => f.attributes?.codigo_agua_balnear && f.geometry)
  .map(f => ({
    json: {
      codigo: f.attributes.codigo_agua_balnear,
      lat: f.geometry.y,
      lon: f.geometry.x
    }
  }));

// Collect all SNIAmb items into a single array item for the Merge node
const sniamb = $input.all().map(i => i.json);
return [{ json: { sniamb } }];

// Collect all praia rows into a single array item
const praias = $input.all().map(i => i.json);
return [{ json: { praias } }];

// Find each dataset by key — safe regardless of Merge output order
const all    = $input.all();
const sniamb = (all.find(i => i.json.sniamb  != null)?.json.sniamb)  ?? [];
const praias = (all.find(i => i.json.praias  != null)?.json.praias)  ?? [];

if (sniamb.length === 0) throw new Error('SNIAmb data is empty — check Buscar SNIAmb node output');
if (praias.length === 0) throw new Error('Praias data is empty — check Buscar Praias node output');

function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(lat1 * Math.PI / 180) *
    Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.asin(Math.sqrt(a));
}

const THRESHOLD_KM = 1.0;
const pairs = []; // { praia_id, codigo }
const usedPraias = new Set();

for (const s of sniamb) {
  if (!s.codigo || s.lat == null || s.lon == null) continue;
  let closest = null, minDist = Infinity;
  for (const p of praias) {
    const d = haversine(s.lat, s.lon, p.latitude, p.longitude);
    if (d < minDist) { minDist = d; closest = p; }
  }
  if (closest && minDist <= THRESHOLD_KM && !usedPraias.has(closest.id)) {
    usedPraias.add(closest.id);
    pairs.push({ praia_id: closest.id, codigo: s.codigo });
  }
}

console.log(`Matched ${pairs.length} beaches out of ${sniamb.length} SNIAmb entries`);

if (pairs.length === 0) throw new Error('No matches found — check coordinates or threshold');

// Build a single bulk UPDATE
const values = pairs.map(p => `(${p.praia_id}, '${p.codigo}')`).join(',\n');
const sql = `
UPDATE praias
SET codigo_agua_balnear = v.codigo
FROM (VALUES ${values}) AS v(id, codigo)
WHERE praias.id = v.id::integer
`;

return [{ json: { sql, matched: pairs.length } }];
